  const [modal, setModal] = useState(null); const [form, setForm] = useState(null); const [historyItem, setHistoryItem] = useState(null); const [search, setSearch] = useState(""); const [riskFilter, setRiskFilter] = useState("all"); const [importText, setImportText] = useState("");

