  function addHistory(existing, type, detail, actor) { return [{ id: uid(), date: new Date().toISOString(), type, detail, actor: actor || setup.deliveryOwner || "Authorized user" }, ...(existing || [])]; }
  function orderName(id) { const order = orders.find((item) => item.id === id); return order ? `${order.orderNumber} · ${order.customer}` : "Order not found"; }
  function openModal(type, value) { const next = value ? deepClone(value) : type === "order" ? blankOrder() : type === "blocker" ? blankBlocker(orders[0]?.id || "") : type === "operation" ? blankOperation(orders[0]?.id || "") : blankShipment(orders[0]?.id || ""); setForm(next); setModal(type); }
  function closeModal() { setModal(null); setForm(null); }
