  function attachEvidence(event, entityType, id) { const files = Array.from(event.target.files || []); if (files.length > 10 || files.reduce((sum, file) => sum + file.size, 0) > 40 * 1024 * 1024) { setNotice("Evidence allows up to 10 files and 40 MB total per record."); return; } evidenceRef.current.set(`${entityType}:${id}`, files); setForm((current) => ({ ...current, evidenceNames: files.map((file) => file.name) })); }
  function duplicateOrder(order) { const copy = deepClone(order); copy.id = uid(); copy.orderNumber = ""; copy.status = "planned"; copy.actualCompletion = ""; copy.actualShipment = ""; copy.history = addHistory([], "Order duplicated", `Planning profile duplicated from ${order.orderNumber}.`); openModal("order", copy); }
